import React, { useState, useEffect, useMemo, useCallback } from 'react';
import axios from 'axios';
import './index.css';

const CODE_PARTICLES = [
  'const app = express();',
  'import React from "react";',
  'npm install --save',
  'function main() {}',
  'git commit -m "init"',
  '<div className="app">',
  'export default App;',
  'console.log("hello");',
  'return { success: true };',
  '#!/usr/bin/env node',
];

// Detect file extension from content
const detectExtension = (content) => {
  const trimmed = content.trim();
  if (trimmed.startsWith('<!DOCTYPE') || trimmed.startsWith('<html')) return '.html';
  if (trimmed.startsWith('{') && trimmed.endsWith('}')) {
    try { JSON.parse(trimmed); return '.json'; } catch (e) { /* not json */ }
  }
  if (trimmed.includes('import React') || trimmed.includes('from "react"')) return '.jsx';
  if (trimmed.includes('const ') || trimmed.includes('let ') || trimmed.includes('function ') || trimmed.includes('=>')) return '.js';
  if (trimmed.startsWith('import ') || trimmed.startsWith('def ') || trimmed.startsWith('class ')) return '.py';
  if (trimmed.includes('body {') || trimmed.includes('@media') || trimmed.includes('.container')) return '.css';
  if (trimmed.startsWith('#!/bin/bash') || trimmed.startsWith('#!/bin/sh')) return '.sh';
  if (trimmed.startsWith('FROM ') && trimmed.includes('RUN ')) return '';
  return '.txt';
};

// Detect language hint for markdown code blocks
const detectLang = (content) => {
  const trimmed = content.trim();
  if (trimmed.includes('import React') || trimmed.includes('from "react"') || trimmed.includes('jsx')) return 'jsx';
  if (trimmed.includes('<!DOCTYPE') || trimmed.includes('<html')) return 'html';
  if (trimmed.includes('body {') || trimmed.includes('@media')) return 'css';
  if (trimmed.startsWith('def ') || trimmed.startsWith('import ') || trimmed.startsWith('class ')) return 'python';
  if (trimmed.startsWith('{')) { try { JSON.parse(trimmed); return 'json'; } catch(e) {} }
  if (trimmed.startsWith('#!/bin/bash')) return 'bash';
  if (trimmed.includes('const ') || trimmed.includes('function ') || trimmed.includes('=>')) return 'javascript';
  return '';
};

// ---- Format converters ----
const filesToPythonDict = (files) => {
  let out = 'files = {\n';
  files.forEach((f, i) => {
    const comma = i < files.length - 1 ? ',' : '';
    if (!f.content.trim()) {
      out += `    "${f.path}": ""${comma}\n`;
    } else {
      out += `    "${f.path}": """${f.content}"""${comma}\n`;
    }
  });
  out += '}\n';
  return out;
};

const filesToMarkdown = (files) => {
  return files.map(f => {
    const lang = detectLang(f.content);
    return `**${f.path}**\n\`\`\`${lang}\n${f.content}\n\`\`\``;
  }).join('\n\n');
};

const filesToDelimiter = (files) => {
  return files.map(f => `==== ${f.path} ====\n${f.content}`).join('\n\n');
};

const OUTPUT_FORMATS = [
  { id: 'python', label: 'Python Dict' },
  { id: 'markdown', label: 'Markdown' },
  { id: 'delimiter', label: 'Delimiter' },
];

const INPUT_MODES = [
  { id: 'smart', label: '🔍 Smart Parse', desc: 'Auto-detect Python dicts, Markdown, delimiters' },
  { id: 'raw', label: '📝 Raw Text', desc: 'Paste raw code → converts to a downloadable file' },
  { id: 'auto', label: '🔄 Auto Format', desc: 'Paste plain text → auto-converts to Python dict, Markdown, or delimiter format' },
];

const App = () => {
  const [inputText, setInputText] = useState('');
  const [parsedFiles, setParsedFiles] = useState([]);
  const [loading, setLoading] = useState(false);
  const [darkMode, setDarkMode] = useState(true);
  const [zipName, setZipName] = useState('project');
  const [statusMsg, setStatusMsg] = useState(null);
  const [inputMode, setInputMode] = useState('smart');
  const [rawFileName, setRawFileName] = useState('');
  const [autoOutputFormat, setAutoOutputFormat] = useState('python');
  const [formattedOutput, setFormattedOutput] = useState('');
  const [copied, setCopied] = useState(false);

  // Apply theme
  useEffect(() => {
    document.documentElement.setAttribute('data-theme', darkMode ? 'dark' : 'light');
  }, [darkMode]);

  // Smart Parser Function
  const parseTextSmart = useCallback((text) => {
    const extractedFiles = [];
    const addFile = (path, content) => {
      const cleanPath = path.trim();
      if (!cleanPath) return;
      if (!extractedFiles.find((f) => f.path === cleanPath)) {
        extractedFiles.push({ path: cleanPath, content });
      }
    };

    try {
      const pythonTripleRegex = /"([^"]+)"\s*:\s*"""([\s\S]*?)"""/g;
      let match;
      while ((match = pythonTripleRegex.exec(text)) !== null) addFile(match[1], match[2]);

      const pythonSingleTripleRegex = /'([^']+)'\s*:\s*'''([\s\S]*?)'''/g;
      while ((match = pythonSingleTripleRegex.exec(text)) !== null) addFile(match[1], match[2]);

      let strippedText = text.replace(/"""[\s\S]*?"""/g, '').replace(/'''[\s\S]*?'''/g, '');
      const pythonEmptyRegex = /"([^"]+)"\s*:\s*""(?!")/g;
      while ((match = pythonEmptyRegex.exec(strippedText)) !== null) addFile(match[1], '');

      const markdownRegex = /\*\*(.*?)\*\*\s*```[a-z]*\n([\s\S]*?)```/g;
      while ((match = markdownRegex.exec(text)) !== null) addFile(match[1], match[2]);

      const markdownAltRegex = /`(.*?)`\s*```[a-z]*\n([\s\S]*?)```/g;
      while ((match = markdownAltRegex.exec(text)) !== null) addFile(match[1], match[2]);

      const delimiterRegex = /====\s*(.*?)\s*====\n([\s\S]*?)(?====\s*.*?\s*====|$)/g;
      while ((match = delimiterRegex.exec(text)) !== null) addFile(match[1], match[2].trim());

      const fileDashedRegex = /File:\s*(.*?)\s*\n----\n([\s\S]*?)\n----/g;
      while ((match = fileDashedRegex.exec(text)) !== null) addFile(match[1], match[2]);

      const commentFileRegex = /(?:\/\/|#)\s*file:\s*(.*?)\s*\n([\s\S]*?)(?=(?:\/\/|#)\s*file:\s*|$)/gi;
      while ((match = commentFileRegex.exec(text)) !== null) addFile(match[1], match[2].trim());

      const dashDelimRegex = /---\s+([\w./\\-]+\.\w+)\s+---\n([\s\S]*?)(?=---\s+[\w./\\-]+\.\w+\s+---|$)/g;
      while ((match = dashDelimRegex.exec(text)) !== null) addFile(match[1], match[2].trim());
    } catch (e) {
      console.error("Parse error:", e);
    }
    return extractedFiles;
  }, []);

  // Raw text parser
  const parseTextRaw = useCallback((text, fileName) => {
    if (!text.trim()) return [];
    const commentFileRegex = /(?:\/\/|#)\s*file:\s*(.*?)\s*\n([\s\S]*?)(?=(?:\/\/|#)\s*file:\s*|$)/gi;
    const multiFiles = [];
    let match;
    while ((match = commentFileRegex.exec(text)) !== null) {
      multiFiles.push({ path: match[1].trim(), content: match[2].trim() });
    }
    if (multiFiles.length > 0) return multiFiles;
    const name = fileName.trim() || `code${detectExtension(text)}`;
    return [{ path: name, content: text }];
  }, []);

  // Auto format parser — detects files from plain text and formats them
  const parseTextAuto = useCallback((text) => {
    if (!text.trim()) return [];
    const files = [];
    const addFile = (path, content) => {
      const cleanPath = path.trim();
      if (!cleanPath) return;
      if (!files.find((f) => f.path === cleanPath)) {
        files.push({ path: cleanPath, content });
      }
    };

    // Try comment markers first: // file: path or # file: path
    const commentFileRegex = /(?:\/\/|#)\s*file:\s*(.*?)\s*\n([\s\S]*?)(?=(?:\/\/|#)\s*file:\s*|$)/gi;
    let match;
    while ((match = commentFileRegex.exec(text)) !== null) {
      addFile(match[1].trim(), match[2].trim());
    }
    if (files.length > 0) return files;

    // Try lines that look like file paths followed by code blocks
    // Pattern: a line that looks like a path (has extension), then code until next path-like line
    const lines = text.split('\n');
    let currentPath = null;
    let currentContent = [];

    const looksLikeFilePath = (line) => {
      const trimmed = line.trim();
      // Must contain a dot for extension, look like a relative path, no spaces (or few)
      return /^[a-zA-Z0-9_./-]+\.[a-zA-Z0-9]+\s*:?\s*$/.test(trimmed) ||
             /^[a-zA-Z0-9_./-]+\.[a-zA-Z0-9]+$/.test(trimmed);
    };

    for (const line of lines) {
      if (looksLikeFilePath(line)) {
        // Save previous file
        if (currentPath) {
          addFile(currentPath, currentContent.join('\n').trim());
        }
        currentPath = line.trim().replace(/:$/, '');
        currentContent = [];
      } else if (currentPath) {
        currentContent.push(line);
      }
    }
    // Save last file
    if (currentPath) {
      addFile(currentPath, currentContent.join('\n').trim());
    }

    // If nothing detected, treat the entire text as a single file
    if (files.length === 0 && text.trim()) {
      const ext = detectExtension(text);
      addFile(`code${ext}`, text.trim());
    }

    return files;
  }, []);

  // Auto-parse on text/mode change
  useEffect(() => {
    let files;
    if (inputMode === 'smart') {
      files = parseTextSmart(inputText);
    } else if (inputMode === 'raw') {
      files = parseTextRaw(inputText, rawFileName);
    } else {
      files = parseTextAuto(inputText);
    }
    setParsedFiles(files);

    // Generate formatted output for Auto mode
    if (inputMode === 'auto' && files.length > 0) {
      let output = '';
      if (autoOutputFormat === 'python') output = filesToPythonDict(files);
      else if (autoOutputFormat === 'markdown') output = filesToMarkdown(files);
      else output = filesToDelimiter(files);
      setFormattedOutput(output);
    } else {
      setFormattedOutput('');
    }

    if (files.length > 0) {
      setStatusMsg({ type: 'info', text: `${files.length} file${files.length > 1 ? 's' : ''} detected` });
    } else if (inputText.trim()) {
      setStatusMsg({ type: 'error', text: inputMode === 'smart'
        ? 'No files detected. Try a different format or switch mode.'
        : inputMode === 'auto'
        ? 'Could not detect files. Try adding "// file: path" markers or "filename.ext" headers.'
        : 'Enter some text to create a file.'
      });
    } else {
      setStatusMsg(null);
    }
  }, [inputText, inputMode, rawFileName, autoOutputFormat, parseTextSmart, parseTextRaw, parseTextAuto]);

  // Regenerate formatted output when format changes
  useEffect(() => {
    if (inputMode === 'auto' && parsedFiles.length > 0) {
      let output = '';
      if (autoOutputFormat === 'python') output = filesToPythonDict(parsedFiles);
      else if (autoOutputFormat === 'markdown') output = filesToMarkdown(parsedFiles);
      else output = filesToDelimiter(parsedFiles);
      setFormattedOutput(output);
    }
  }, [autoOutputFormat, parsedFiles, inputMode]);

  // File tree grouped by folder
  const fileTree = useMemo(() => {
    const tree = {};
    parsedFiles.forEach(file => {
      const parts = file.path.split('/');
      const root = parts.length > 1 ? parts[0] : '📄 Root';
      if (!tree[root]) tree[root] = [];
      tree[root].push(file.path);
    });
    return tree;
  }, [parsedFiles]);

  // Copy formatted output
  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(formattedOutput);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Copy failed:', err);
    }
  };

  // Download handler
  const handleDownload = async () => {
    if (parsedFiles.length === 0) return;
    setLoading(true);
    setStatusMsg({ type: 'info', text: 'Generating ZIP...' });

    try {
      const response = await axios.post(
        'http://localhost:5001/create-zip',
        { files: parsedFiles },
        { responseType: 'blob' }
      );

      const blob = new Blob([response.data], { type: 'application/zip' });
      const fileName = `${zipName || 'project'}.zip`;

      if (window.showSaveFilePicker) {
        try {
          const handle = await window.showSaveFilePicker({
            suggestedName: fileName,
            types: [{ description: 'ZIP Archive', accept: { 'application/zip': ['.zip'] } }],
          });
          const writable = await handle.createWritable();
          await writable.write(blob);
          await writable.close();
          setStatusMsg({ type: 'success', text: `Saved ${fileName} successfully!` });
          setLoading(false);
          return;
        } catch (pickerErr) {
          if (pickerErr.name === 'AbortError') {
            setStatusMsg(null);
            setLoading(false);
            return;
          }
        }
      }

      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', fileName);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
      setStatusMsg({ type: 'success', text: `Downloaded ${fileName}!` });
    } catch (error) {
      console.error('Error downloading:', error);
      setStatusMsg({ type: 'error', text: 'Failed to generate ZIP. Is the backend running?' });
    }
    setLoading(false);
  };

  return (
    <>
      {/* Animated Background */}
      <div className="app-background">
        {CODE_PARTICLES.map((code, i) => (
          <span
            key={i}
            className="particle"
            style={{
              left: `${(i * 10) + 2}%`,
              animationDuration: `${18 + i * 3}s`,
              animationDelay: `${i * 2}s`,
              fontSize: `${12 + (i % 3) * 2}px`,
            }}
          >
            {code}
          </span>
        ))}
      </div>

      {/* Main App */}
      <div className="app-container">
        {/* Header */}
        <header className="app-header">
          <div className="app-title">
            <div className="logo-icon">⚡</div>
            <div>
              <h1>Code → ZIP</h1>
              <p className="app-subtitle">Paste code, preview structure, download as ZIP</p>
            </div>
          </div>
          <button className="theme-toggle" onClick={() => setDarkMode(!darkMode)}>
            {darkMode ? '☀️' : '🌙'} {darkMode ? 'Light' : 'Dark'}
          </button>
        </header>

        {/* Main Layout */}
        <div className="main-layout">
          {/* Left: Editor */}
          <div className="glass-panel editor-panel">
            {/* Mode Tabs */}
            <div className="mode-tabs">
              {INPUT_MODES.map(mode => (
                <button
                  key={mode.id}
                  className={`mode-tab ${inputMode === mode.id ? 'active' : ''}`}
                  onClick={() => setInputMode(mode.id)}
                >
                  {mode.label}
                </button>
              ))}
            </div>

            <p className="panel-desc">
              {INPUT_MODES.find(m => m.id === inputMode)?.desc}
            </p>

            {/* Raw mode: filename input */}
            {inputMode === 'raw' && (
              <input
                className="raw-filename-input"
                type="text"
                value={rawFileName}
                onChange={(e) => setRawFileName(e.target.value)}
                placeholder="File path (e.g. src/App.js) — or leave empty for auto-detect"
              />
            )}

            {/* Auto mode: format selector */}
            {inputMode === 'auto' && (
              <div className="format-selector">
                <span className="format-label">Output format:</span>
                {OUTPUT_FORMATS.map(fmt => (
                  <button
                    key={fmt.id}
                    className={`format-btn ${autoOutputFormat === fmt.id ? 'active' : ''}`}
                    onClick={() => setAutoOutputFormat(fmt.id)}
                  >
                    {fmt.label}
                  </button>
                ))}
              </div>
            )}

            {statusMsg && (
              <div className={`status-bar ${statusMsg.type}`}>
                <span>{statusMsg.type === 'success' ? '✅' : statusMsg.type === 'error' ? '⚠️' : 'ℹ️'}</span>
                <span>{statusMsg.text}</span>
              </div>
            )}

            <textarea
              className="code-textarea"
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder={inputMode === 'smart'
                ? `Paste formatted code here...\n\nSupported formats:\n\n─── Python Dictionary ───\n"src/App.js": """const App = () => {};"""\n\n─── Markdown ───\n**src/App.js**\n\`\`\`javascript\nconst App = () => {};\n\`\`\`\n\n─── Delimiters ───\n==== src/App.js ====\nconst App = () => {};`
                : inputMode === 'auto'
                ? `Paste plain text here to auto-format...\n\nTip: Use "// file: path" markers or put filenames\non their own line:\n\nsrc/App.js\nimport React from 'react';\nconst App = () => <div>Hello</div>;\nexport default App;\n\nsrc/index.css\nbody { margin: 0; }\n\nThe output will be auto-converted to your\nchosen format (Python dict, Markdown, etc.)`
                : `Paste any raw code here...\n\nIt will be saved as a single file.\nSet the filename above, or leave it empty\nand we'll auto-detect the type.\n\n─── Multi-file tip ───\n// file: src/index.js\nconsole.log("hello");\n\n// file: src/utils.js\nexport const add = (a, b) => a + b;`
              }
            />

            {/* Auto mode: formatted output */}
            {inputMode === 'auto' && formattedOutput && (
              <div className="formatted-output-section">
                <div className="formatted-output-header">
                  <span className="formatted-output-title">📋 Formatted Output</span>
                  <button className="copy-btn" onClick={handleCopy}>
                    {copied ? '✅ Copied!' : '📋 Copy'}
                  </button>
                </div>
                <textarea
                  className="code-textarea formatted-output"
                  value={formattedOutput}
                  readOnly
                />
              </div>
            )}
          </div>

          {/* Right: Preview + Download */}
          <div className="glass-panel sidebar-panel">
            <div className="sidebar-header">
              <h2>📁 File Structure</h2>
              <span className="file-count-badge">{parsedFiles.length} files</span>
            </div>

            {/* File Tree */}
            <div className="file-tree">
              {parsedFiles.length === 0 ? (
                <div className="file-tree-empty">
                  <span className="empty-icon">📂</span>
                  <span>No files detected yet</span>
                  <span style={{ fontSize: 11, opacity: 0.7 }}>Paste code on the left to see the structure</span>
                </div>
              ) : (
                Object.keys(fileTree).sort().map(folder => (
                  <div key={folder} className="folder-group">
                    <div className="folder-name">
                      <span className="folder-icon">📁</span>
                      {folder}
                    </div>
                    {fileTree[folder].map(filePath => (
                      <div key={filePath} className="file-item" title={filePath}>
                        <span className="file-icon">📄</span>
                        <span>{filePath.includes('/') ? filePath.substring(filePath.lastIndexOf('/') + 1) : filePath}</span>
                      </div>
                    ))}
                  </div>
                ))
              )}
            </div>

            {/* Download Section */}
            <div className="download-section">
              <input
                className="rename-input"
                type="text"
                value={zipName}
                onChange={(e) => setZipName(e.target.value)}
                placeholder="Enter ZIP file name..."
              />
              <button
                className="download-btn"
                onClick={handleDownload}
                disabled={loading || parsedFiles.length === 0}
              >
                {loading ? (
                  <>
                    <span className="spinner"></span>
                    Generating...
                  </>
                ) : (
                  <>
                    💾 Download {zipName || 'project'}.zip
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default App;
